-- Migration: 100일 → 30일 커리큘럼 재구성
--
-- Step 2: curriculum_day 100행 삭제 → CHECK 제약 수정 → 30행 삽입
--
-- 주의: 기존 curriculum_unit / curriculum_step / sentences 데이터는 건드리지 않는다.
-- curriculum_day 행만 재구성하고, 새 브릿지 테이블로 N:1 매핑한다.

-- =========================================================================
-- 1. 기존 curriculum_day 100행 삭제
-- =========================================================================
DELETE FROM curriculum_day;

-- =========================================================================
-- 2. CHECK 제약 수정 (day_number 1~30, cefr_level에 B2 추가)
-- =========================================================================
ALTER TABLE curriculum_day DROP CONSTRAINT IF EXISTS curriculum_day_day_number_check;
ALTER TABLE curriculum_day ADD CONSTRAINT curriculum_day_day_number_check CHECK (day_number >= 1 AND day_number <= 30);

ALTER TABLE curriculum_day DROP CONSTRAINT IF EXISTS curriculum_day_cefr_level_check;
ALTER TABLE curriculum_day ADD CONSTRAINT curriculum_day_cefr_level_check CHECK (cefr_level = ANY (ARRAY['A1','A2','B1','B2']));

-- =========================================================================
-- 3. 새 30행 삽입 (unit_id는 첫 번째 unit 참조 — DROP 전 하위 호환)
-- =========================================================================
ON CONFLICT (id) DO NOTHING;
